INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'independent_contractor',
  'us_new_york',
  1,
  'Independent Contractor Agreement (New York)',
  'This Independent Contractor Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}}, with an address at {{party_a_address}} ("Client"), and {{party_b_company}}, with an address at {{party_b_address}} ("Contractor"). Client and Contractor may be referred to individually as a "Party" and collectively as the "Parties".',
  'WHEREAS, Client desires to retain Contractor to perform certain services described in this Agreement; and
WHEREAS, Contractor represents that Contractor has the expertise, resources, and ability to perform such services as an independent contractor;
NOW, THEREFORE, in consideration of the mutual covenants and promises contained herein, the Parties agree as follows:',
  '[{"id":"services","title":"1. SERVICES","content":"1.1 Services. Contractor shall perform the services described in {{services_description}} (the \"Services\") in a professional and workmanlike manner, consistent with generally accepted industry standards.\n\n1.2 Deliverables; Schedule. Any deliverables, milestones, deadlines, and acceptance criteria shall be as specified in {{services_description}} or as otherwise agreed in writing.\n\n1.3 Place and Manner of Performance. Contractor will determine the method, details, and means of performing the Services; provided that Contractor shall reasonably cooperate with Client''s operational and security policies when accessing Client''s facilities or systems.\n\n1.4 Changes. Any material change affecting scope, timeline, or compensation must be agreed to in writing by both Parties.\n\n1.5 No Authority. Contractor has no authority to bind Client or make representations on Client''s behalf unless expressly authorized in writing.","type":"standard","order":1},{"id":"compensation_fifa","title":"2. COMPENSATION; INVOICING; FREELANCE ISN''T FREE ACT COMPLIANCE","content":"2.1 Fees. As full consideration for the Services, Client shall pay Contractor: (a) a total fee of {{payment_amount}} and/or (b) an hourly rate of {{hourly_rate}}, as specified in {{services_description}}.\n\n2.2 Freelance Isn''t Free Act (FIFA) Compliance. If the total value of the Services is $800 or more (whether per project or aggregated over 120 days), this Agreement is subject to the New York City Freelance Isn''t Free Act (NYC Admin. Code § 20-927 et seq.) and/or the New York State Freelance Isn''t Free Act (NY Labor Law § 191-d). Accordingly:\n(a) This written Agreement sets forth the scope of Services, compensation, and payment terms;\n(b) Client shall pay all compensation due to Contractor no later than 30 days after completion of the Services, or as otherwise specified in this Agreement;\n(c) Client shall not require Contractor to accept less than the contracted amount as a condition of timely payment;\n(d) Client shall not threaten or take any action against Contractor that penalizes Contractor for or deters Contractor from exercising rights under the Freelance Isn''t Free Act.\n\n2.3 Invoicing and Payment. Contractor shall invoice Client as stated in {{services_description}}. Unless otherwise stated, Client shall pay undisputed amounts within 30 days of completion of the Services or receipt of a proper invoice, whichever is applicable.\n\n2.4 Late Payment. If Client fails to pay timely, Contractor may be entitled to double damages, injunctive relief, and reasonable attorney''s fees under the Freelance Isn''t Free Act.\n\n2.5 Expenses. Unless expressly authorized in advance in writing, Contractor is responsible for all expenses incurred in performing the Services.\n\n2.6 Taxes. Contractor is solely responsible for all federal, state, and local taxes arising from compensation paid under this Agreement, including New York State and City income taxes and self-employment tax. Client will not withhold or pay payroll taxes for Contractor.\n\n2.7 No Employee Benefits. Contractor acknowledges that Contractor is not eligible for Client-provided benefits, including workers'' compensation (except as required by law), unemployment insurance, health insurance, retirement benefits, or paid leave.","type":"standard","order":2},{"id":"independent_contractor_status","title":"3. INDEPENDENT CONTRACTOR STATUS; NY LABOR LAW COMPLIANCE","content":"3.1 Independent Contractor. Contractor is an independent contractor and not an employee, partner, joint venturer, agent, or representative of Client. Contractor shall control the manner and means of performing the Services.\n\n3.2 No Employment Relationship. Nothing in this Agreement shall be construed to create an employment relationship. Contractor shall not represent that Contractor is an employee of Client.\n\n3.3 New York Classification Compliance. The Parties intend that Contractor be properly classified as an independent contractor under applicable New York law, including the New York Labor Law and Department of Labor guidelines. Contractor represents and warrants that Contractor meets the applicable criteria for independent contractor status under the common law \"right to control\" test and any applicable statutory tests, including that:\n(a) Contractor is free from Client''s control and direction in performing the Services, both under this Agreement and in fact;\n(b) Contractor is customarily engaged in an independently established trade, occupation, or business of the same nature as the Services;\n(c) Contractor has the opportunity for profit or loss depending on managerial skill;\n(d) Contractor has an investment in facilities, equipment, or the business; and\n(e) Contractor has the right to hire others and to work for other clients.\n\n3.4 ABC Test Awareness. The Parties acknowledge that New York uses various tests for worker classification depending on the regulatory context (e.g., unemployment insurance, workers'' compensation), including an \"ABC\" test for certain purposes. Contractor represents compliance with applicable tests.\n\n3.5 Contractor''s Business. Contractor is responsible for providing tools, equipment, and materials necessary to perform the Services, maintaining required business licenses and permits, and operating Contractor''s business in compliance with applicable law.\n\n3.6 Non-Exclusivity. Unless otherwise stated, Contractor may perform services for others during the Term, provided such services do not materially interfere with Contractor''s performance or breach this Agreement.","type":"standard","order":3},{"id":"term_termination","title":"4. TERM; TERMINATION","content":"4.1 Term. This Agreement begins on the Effective Date and continues until {{expiration_date}}, unless earlier terminated (the \"Term\"). If no expiration date is specified, the Term continues until completion of the Services or termination.\n\n4.2 Termination for Convenience. Either Party may terminate this Agreement upon {{notice_period}} days'' written notice.\n\n4.3 Termination for Cause. Either Party may terminate immediately upon written notice if the other Party: (a) materially breaches and fails to cure within 10 days after receiving written notice; (b) becomes insolvent or files for bankruptcy; or (c) engages in fraud, willful misconduct, or unlawful conduct.\n\n4.4 Effect of Termination. Upon termination: (a) Contractor shall stop work and deliver all Client property and Work Product; (b) Client shall pay for Services properly performed through the termination date within the payment timeframes required under Section 2.\n\n4.5 Survival. Sections 5, 6, 7, 8, and 10 shall survive termination.","type":"standard","order":4},{"id":"intellectual_property","title":"5. INTELLECTUAL PROPERTY; WORK PRODUCT","content":"5.1 Work Product. \"Work Product\" means all deliverables, inventions, discoveries, developments, designs, works of authorship, documentation, software, and other materials created by Contractor in connection with the Services.\n\n5.2 Ownership; Assignment. Client shall own all right, title, and interest in the Work Product. Contractor hereby assigns to Client all rights in the Work Product, including all intellectual property rights.\n\n5.3 Further Assurances. Contractor shall execute documents and take actions as Client may reasonably request to perfect Client''s rights in the Work Product.\n\n5.4 Background Technology. Contractor retains rights in technology owned or developed outside this Agreement (\"Background Technology\"). If Contractor incorporates Background Technology into Work Product, Contractor grants Client a perpetual, irrevocable, worldwide, royalty-free, transferable, sublicensable license to use such Background Technology as part of the Work Product.\n\n5.5 Moral Rights Waiver. Contractor waives any \"moral rights\" in the Work Product to the extent permitted by law.","type":"negotiable","order":5},{"id":"confidentiality","title":"6. CONFIDENTIALITY; TRADE SECRETS","content":"6.1 Confidential Information. \"Confidential Information\" means any non-public information disclosed by Client that is designated as confidential or should reasonably be understood as confidential. Confidential Information includes trade secrets as recognized under New York common law and the federal Defend Trade Secrets Act.\n\n6.2 Exclusions. Confidential Information excludes information that: (a) is publicly available; (b) was known before disclosure; (c) is received from a third party without restriction; or (d) is independently developed.\n\n6.3 Obligations. Contractor shall: (a) use Confidential Information solely to perform the Services; (b) protect Confidential Information with reasonable care; (c) not disclose Confidential Information except to personnel bound by confidentiality; and (d) promptly notify Client of any suspected unauthorized disclosure.\n\n6.4 Return/Destruction. Upon request or termination, Contractor shall return or destroy all Confidential Information.\n\n6.5 Defend Trade Secrets Act Notice. Pursuant to 18 U.S.C. § 1833(b), an individual shall not be held liable for disclosure of a trade secret made in confidence to a government official or attorney for reporting or investigating suspected violations of law, or in a sealed court filing.\n\n6.6 Injunctive Relief. Contractor acknowledges that breach may cause irreparable harm. Client is entitled to seek injunctive relief.","type":"standard","order":6},{"id":"representations_warranties","title":"7. REPRESENTATIONS AND WARRANTIES","content":"7.1 Mutual Authority. Each Party represents that it has authority to enter into this Agreement.\n\n7.2 Contractor Warranties. Contractor represents and warrants that: (a) Contractor has the skill and experience to perform the Services; (b) Services will be performed professionally and in compliance with applicable law; (c) Work Product will not infringe third-party intellectual property rights; (d) Contractor will not introduce malicious code into Client''s systems; and (e) Contractor''s performance does not violate any agreement with a third party.\n\n7.3 Disclaimer. Except as stated, neither Party makes any other warranties, express or implied, including implied warranties of merchantability or fitness for a particular purpose.","type":"standard","order":7},{"id":"indemnification","title":"8. INDEMNIFICATION; LIMITATION OF LIABILITY","content":"8.1 Contractor Indemnification. Contractor shall defend, indemnify, and hold harmless Client from third-party claims arising from: (a) Contractor''s negligence or willful misconduct; (b) Contractor''s breach of this Agreement; (c) Work Product infringing third-party intellectual property rights; or (d) Contractor''s violation of law.\n\n8.2 Client Indemnification. Client shall defend, indemnify, and hold harmless Contractor from third-party claims arising from Client-provided materials that infringe third-party rights.\n\n8.3 Limitation of Liability. Neither Party shall be liable for indirect, incidental, special, consequential, or punitive damages. Nothing limits liability for fraud, willful misconduct, or liability that cannot be limited under applicable law.","type":"negotiable","order":8},{"id":"insurance","title":"9. INSURANCE (OPTIONAL)","content":"9.1 Coverage. If required by Client in writing, Contractor shall maintain appropriate insurance coverage for the Services.\n\n9.2 Proof of Insurance. Upon request, Contractor shall provide certificates of insurance.\n\n9.3 No Limitation. Insurance does not limit Contractor''s obligations or liability under this Agreement.","type":"optional","order":9},{"id":"discrimination_whistleblower","title":"10. NON-DISCRIMINATION; WHISTLEBLOWER PROTECTIONS","content":"10.1 Non-Discrimination. The Parties shall comply with the New York State Human Rights Law (NY Executive Law Article 15) and the New York City Human Rights Law (NYC Admin. Code Title 8), which prohibit discrimination against independent contractors based on protected characteristics.\n\n10.2 Whistleblower Protections. The Parties acknowledge the protections afforded under New York Labor Law § 740 (whistleblower protection), which protects workers (including independent contractors in certain circumstances) from retaliation for reporting violations of law.\n\n10.3 No Retaliation. Client shall not take any adverse action against Contractor in retaliation for: (a) exercising rights under the Freelance Isn''t Free Act; (b) filing a complaint or participating in an investigation; or (c) reporting suspected violations of law to appropriate authorities.","type":"standard","order":10},{"id":"restrictive_covenants","title":"11. RESTRICTIVE COVENANTS (NEW YORK)","content":"11.1 Non-Compete Limitations. The Parties acknowledge that under New York law, non-compete agreements are strictly scrutinized and will only be enforced to the extent they are: (a) no greater than required to protect a legitimate business interest; (b) not unreasonably burdensome to the restricted party; (c) not harmful to the public; and (d) reasonable in time, geography, and scope.\n\n11.2 Non-Solicitation. During the Term and for {{non_solicitation_period}} months thereafter, Contractor shall not solicit Client''s employees or customers with whom Contractor had material contact during the engagement, provided such restriction is reasonable.\n\n11.3 Reformation. If any restrictive covenant is deemed unenforceable, the Parties agree that a court may reform such covenant to make it enforceable under New York law.","type":"optional","order":11},{"id":"governing_law","title":"12. GOVERNING LAW; VENUE; GENERAL PROVISIONS","content":"12.1 Governing Law. This Agreement shall be governed by the laws of the State of New York, without regard to conflict of laws principles.\n\n12.2 Venue. The Parties consent to exclusive jurisdiction of the state and federal courts in {{venue_county}} County, New York.\n\n12.3 Notices. Notices must be in writing and delivered personally, by overnight courier, certified mail, or email with confirmation.\n\n12.4 Assignment. Contractor may not assign without Client''s prior written consent. Client may assign in connection with a merger, acquisition, or sale of assets.\n\n12.5 Subcontractors. Contractor may not use subcontractors without Client''s prior written consent. Contractor remains responsible for subcontractors.\n\n12.6 Compliance. Each Party shall comply with applicable laws.\n\n12.7 Severability. Invalid provisions shall be enforced to the maximum extent permitted by law.\n\n12.8 Waiver. Waivers must be in writing.\n\n12.9 Entire Agreement. This Agreement is the entire agreement and supersedes prior understandings. Amendments must be in writing signed by both Parties.\n\n12.10 Counterparts; Electronic Signatures. May be executed in counterparts. Electronic signatures are enforceable under the New York Electronic Signatures and Records Act (ESRA, NY State Tech. Law Article 3) and the federal ESIGN Act.\n\n12.11 Force Majeure. Neither Party is liable for delays due to causes beyond reasonable control.\n\n12.12 Record Retention. Client shall retain a copy of this Agreement for at least 6 years as required by the Freelance Isn''t Free Act.","type":"standard","order":12}]'::jsonb,
  'IN WITNESS WHEREOF, the Parties have executed this Agreement as of {{signature_date}}.

