:"dates","type":"date","required":false},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"venue_county","token":"{{venue_county}}","label":"Venue County","description":"New York county for legal venue (e.g., New York, Kings, Queens)","category":"terms","type":"text","required":true},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period","description":"Days notice for termination","category":"terms","type":"number","required":false},{"id":"non_solicitation_period","token":"{{non_solicitation_period}}","label":"Non-Solicitation Period","description":"Months for non-solicitation restriction","category":"terms","type":"number","required":false},{"id":"hourly_rate","token":"{{hourly_rate}}","label":"Hourly Rate","description":"Rate per hour","category":"financial","type":"currency","required":false},{"id":"payment_amount","token":"{{payment_amount}}","label":"Payment Amount","description":"Total fee","category":"financial","type":"currency","required":false},{"id":"services_description","token":"{{services_description}}","label":"Services Description","description":"Description of services","category":"project","type":"textarea","required":false}]'::jsonb,
